// Extract inverter SN from topic: envertech/{sn}/status
const parts = msg.topic.split('/');
const inverterSn = parts[1];

// Skip the combined virtual device
if (inverterSn === 'combined') return null;

const data = msg.payload;
if (!data || data.total_power === undefined) return null;

const points = [];

// Inverter-level measurement
points.push({
    measurement: 'solar_inverter',
    tags: { inverter_sn: inverterSn },
    fields: {
        total_power:  parseFloat(data.total_power)  || 0,
        total_energy: parseFloat(data.total_energy) || 0,
        panel_count:  parseInt(data.panel_count)    || 0,
    }
});

// Per-panel measurements
const panelCount = parseInt(data.panel_count) || 0;
for (let i = 0; i < panelCount; i++) {
    const panel = data['panel_' + i];
    if (!panel) continue;
    points.push({
        measurement: 'solar_panel',
        tags: {
            inverter_sn: inverterSn,
            panel_index: String(i),
            panel_sn:    panel.mi_sn || 'unknown',
        },
        fields: {
            power:         parseFloat(panel.power)         || 0,
            energy:        parseFloat(panel.energy)        || 0,
            input_voltage: parseFloat(panel.input_voltage) || 0,
            temperature:   parseFloat(panel.temperature)   || 0,
            grid_voltage:  parseFloat(panel.grid_voltage)  || 0,
            frequency:     parseFloat(panel.frequency)     || 0,
        }
    });
}

msg.payload = points;
return msg;

const data = msg.payload;
if (!data || data.total_power === undefined) return null;

msg.payload = [{
    measurement: 'solar_combined',
    tags: { source: 'all_inverters' },
    fields: {
        total_power:  parseFloat(data.total_power)  || 0,
        total_energy: parseFloat(data.total_energy) || 0,
        panel_count:  parseInt(data.panel_count)    || 0,
    }
}];
return msg;
